    "cases.capture_daywork_and_time_and_materials.step.submit.what": "Procijenite dogovorene resurse prema ugovornim cijenama ili postocima za režijski rad, priložite potpisane obrasce i nalog, i podnesite obračun kako bi ušao u sljedeće plaćanje.",
    "cases.capture_daywork_and_time_and_materials.step.submit.why": "Režijski rad koji nikad nije procijenjen i podnesen posao je koji ste odradili besplatno. Pretvaranje potpisanog zapisa u obračun prema ugovoru korak je koji trud stvarno pretvara u novac.",
    "cases.capture_daywork_and_time_and_materials.title": "Zabilježite režijski rad i utrošak vremena i materijala",
    "cases.carbon_from_bim_6d.desc": "Pretvorite konvertirani BIM model u otisak ugrađenog ugljika. Automatsko obogaćivanje očitava količine iz geometrije i uparuje svaki materijal s emisijskim faktorom, zatim postavljate cilj smanjenja i izdajete izvještaj. Pet koraka.",
    "cases.carbon_from_bim_6d.step.enrich.in.factors": "Baza emisijskih faktora",
    "cases.carbon_from_bim_6d.step.enrich.in.inventory": "Otvoren inventar",
    "cases.carbon_from_bim_6d.step.enrich.in.materials": "Materijali elemenata",
    "cases.carbon_from_bim_6d.step.enrich.out.entries": "Potvrđeni unosi ugljika",
    "cases.carbon_from_bim_6d.step.enrich.out.preview": "Pregled uparenih stavki",
    "cases.carbon_from_bim_6d.step.enrich.title": "Automatski obogatite ugrađeni ugljik iz BIM-a",
    "cases.carbon_from_bim_6d.step.enrich.what": "Pokrenite automatsko obogaćivanje iz BIM-a unutar inventara. Odaberite model, pregledajte predložene stavke u pregledu, zatim potvrdite. Svaki materijal elementa uparen je s emisijskim faktorom, a količina se izravno preuzima iz geometrije. Ništa se ne sprema dok ne prihvatite.",
    "cases.carbon_from_bim_6d.step.enrich.why": "Ovdje 6D pokazuje svoju vrijednost. Umjesto ručnog unosa betona, čelika i izolacije stavku po stavku, dobivate potpun popis ugrađenog ugljika iz modela u sekundama, a svaki redak pokazuje koliko je uparivanje pouzdano.",
    "cases.carbon_from_bim_6d.step.import-model.in.file": "Konvertirana datoteka modela",
    "cases.carbon_from_bim_6d.step.import-model.in.project": "Projektni zapis",
    "cases.carbon_from_bim_6d.step.import-model.out.elements": "Elementi s materijalima",
    "cases.carbon_from_bim_6d.step.import-model.out.quantities": "Količine iz geometrije",
    "cases.carbon_from_bim_6d.step.import-model.title": "Uvezite BIM model",
    "cases.carbon_from_bim_6d.step.import-model.what": "Otvorite BIM i uvezite konvertirani model za ovaj posao. Kad konverzija završi, svaki zid, ploča i stup nosi oznaku materijala i količinu izmjerenu iz pune geometrije.",
    "cases.carbon_from_bim_6d.step.import-model.why": "Cijeli otisak čita se iz modela, pa loš ulaz znači loš izlaz. Konvertiran model daje uparivanju ugljika čist materijal i stvarnu količinu umjesto broja koji je netko ručno upisao.",
    "cases.carbon_from_bim_6d.step.inventory.in.model": "Uvezen BIM model",
    "cases.carbon_from_bim_6d.step.inventory.in.project": "Projektni zapis",
    "cases.carbon_from_bim_6d.step.inventory.out.boundary": "Postavljena sistemska granica",
    "cases.carbon_from_bim_6d.step.inventory.out.inventory": "Prazan inventar ugljika",
    "cases.carbon_from_bim_6d.step.inventory.title": "Otvorite Ugljik i pokrenite inventar",
    "cases.carbon_from_bim_6d.step.inventory.what": "Prijeđite na Ugljik i otvorite novi inventar za projekt. Odredite sistemsku granicu unaprijed, od izvora do vrata za ljusku zgrade ili od izvora do groba kada trebate i fazu uporabe i kraja životnog vijeka.",
    "cases.carbon_from_bim_6d.step.inventory.why": "Izbor granice određuje cijeli rezultat, pa je odredite prije nego ijedan unos uđe. Dva otiska usporediva su samo ako pokrivaju iste faze, a inventar je jedino mjesto gdje se zbraja svaki redak materijala.",
    "cases.carbon_from_bim_6d.step.review.in.confidence": "Oznake pouzdanosti uparivanja",
    "cases.carbon_from_bim_6d.step.review.in.entries": "Obogaćeni unosi ugljika",
    "cases.carbon_from_bim_6d.step.review.out.footprint": "Odobren otisak",
    "cases.carbon_from_bim_6d.step.review.out.verified": "Provjerene stavke ugljika",
    "cases.carbon_from_bim_6d.step.review.title": "Pregledajte povezane unose i pouzdanost",
    "cases.carbon_from_bim_6d.step.review.what": "Prođite kroz dodane stavke. Svaki unos upućuje na BIM element koji ga je proizveo i pokazuje pouzdanost uparivanja, pa najprije otvorite žute i crvene retke i ispravite faktor ili količinu gdje uparivanje izgleda pogrešno.",
    "cases.carbon_from_bim_6d.step.review.why": "Alat predlaže, procjenitelj odobrava. Generički faktor na specijaliziranom proizvodu može promijeniti ukupan iznos za tone, pa oznaka pouzdanosti pokazuje točno koji recima trebaju drugi pogled.",
    "cases.carbon_from_bim_6d.step.target.in.area": "Površina",
    "cases.carbon_from_bim_6d.step.target.in.footprint": "Provjeren otisak",
    "cases.carbon_from_bim_6d.step.target.out.report": "Izvještaj o ugljiku",
    "cases.carbon_from_bim_6d.step.target.out.target": "Cilj smanjenja",
    "cases.carbon_from_bim_6d.step.target.title": "Postavite cilj i izvijestite",
    "cases.carbon_from_bim_6d.step.target.what": "Postavite cilj smanjenja, kao apsolutan ukupan iznos ili po kvadratnom metru površine, zatim izradite izvještaj za razdoblje u okviru koji klijent traži. Cilj se ažurira uživo kako se inventar mijenja.",
    "cases.carbon_from_bim_6d.step.target.why": "Sirov broj ugljika sam po sebi nikoga ne uvjerava. Cilj povlači liniju koju pokušavate nadmašiti, a izvezeni izvještaj pretvara otisak u datiran zapis koji možete pokazati procjenitelju ili službi za planiranje.",
    "cases.carbon_from_bim_6d.title": "Dobijte 6D ugljik iz BIM modela",
    "cases.change_register_and_impact.desc": "Zabilježite svaku izmjenu u jednom registru, očitajte utjecaj na vrijeme i trošak u odnosu na stvarnu projektnu evidenciju, i predočite trend klijentu prije nego postane iznenađenje.",
