    "cases.give_the_client_a_project_portal.step.pack.in.photos": "Fotografije napretka",
    "cases.give_the_client_a_project_portal.step.pack.in.summary": "Sažetak razdoblja",
    "cases.give_the_client_a_project_portal.step.pack.out.pack": "Paket napretka za naručitelja",
    "cases.give_the_client_a_project_portal.step.pack.out.published": "Objavljeno na portalu",
    "cases.give_the_client_a_project_portal.step.pack.title": "Objavi paket napretka",
    "cases.give_the_client_a_project_portal.step.pack.what": "Generirajte paket napretka za naručitelja, fotografije, postotak dovršenosti i sažetak razdoblja, i objavite ga izravno na portal istog dana svakog mjeseca. Naručitelj ga čita u svoje vrijeme.",
    "cases.give_the_client_a_project_portal.step.pack.why": "Datirani paket koji naručitelj sam preuzima dokaz je da je posao izviješten, na vrijeme, svako razdoblje. Zamjenjuje mjesečni sastanak koji nikad ne pokrije baš sve i nikad se ne zapiše.",
    "cases.give_the_client_a_project_portal.step.payment.in.application": "Zahtjev za plaćanje",
    "cases.give_the_client_a_project_portal.step.payment.in.certified": "Ovjereno stanje plaćanja",
    "cases.give_the_client_a_project_portal.step.payment.in.portal": "Portal za naručitelja",
    "cases.give_the_client_a_project_portal.step.payment.out.published": "Objavljen iznos plaćanja",
    "cases.give_the_client_a_project_portal.step.payment.out.shared": "Podijeljen odobreni iznos",
    "cases.give_the_client_a_project_portal.step.payment.title": "Objavi odobreno stanje plaćanja",
    "cases.give_the_client_a_project_portal.step.payment.what": "Objavite ovjereno stanje plaćanja na portalu, što je zatraženo, što je odobreno i što dospijeva, tako da naručitelj vidi isti iznos kao i vi. Objavljuju se samo dogovoreni brojevi, ne radne kalkulacije.",
    "cases.give_the_client_a_project_portal.step.payment.why": "Sporovi oko plaćanja obično počinju od dviju različitih tablica. Jedan odobreni iznos koji obje strane vide sprječava spor i omogućuje pravodobnu naplatu računa.",
    "cases.give_the_client_a_project_portal.step.portal.in.documents": "Podijeljeni skup dokumenata",
    "cases.give_the_client_a_project_portal.step.portal.in.progress": "Napredak i obračuni",
    "cases.give_the_client_a_project_portal.step.portal.in.visibility": "Postavke vidljivosti",
    "cases.give_the_client_a_project_portal.step.portal.out.access": "Pristup portalu za naručitelja",
    "cases.give_the_client_a_project_portal.step.portal.out.view": "Pregled samo za čitanje za naručitelja",
    "cases.give_the_client_a_project_portal.step.portal.title": "Odaberi što naručitelj vidi",
    "cases.give_the_client_a_project_portal.step.portal.what": "Na portalu uključite ploče koje naručitelj treba imati, napredak, obračune i podijeljeni skup dokumenata, a isključite sve interno poput vašeg troška ili marže. Postavite jednom i dobivaju pregled samo za čitanje koji se sam ažurira.",
    "cases.give_the_client_a_project_portal.step.portal.why": "Naručitelj s vlastitim uvidom u stvarnom vremenu prestaje zvati za ažuriranja i nagađati. Kontrola točno onoga što je podijeljeno čuva vaš trošak i internu korespondenciju privatnima, dok posao i dalje izgleda otvoreno.",
    "cases.give_the_client_a_project_portal.title": "Osiguraj naručitelju portal projekta",
    "cases.handover_and_closeout.desc": "Uredno završite posao: svedite popis nedostataka na nulu, potvrdite da su sve inspekcije prošle i da nema otvorenih neusklađenosti, prikupite dokumentaciju izvedenog stanja i izdajte potpisanu primopredaju.",
    "cases.handover_and_closeout.step.closeout.in.checklist": "Kontrolni popis za primopredaju",
    "cases.handover_and_closeout.step.closeout.in.docs": "Potpun skup dokumenata",
    "cases.handover_and_closeout.step.closeout.out.defects": "Pokrenut jamstveni rok",
