    "cases.independent_cost_check_on_a_design.step.benchmark.in.rates": "Cijene velike vrijednosti",
    "cases.independent_cost_check_on_a_design.step.benchmark.out.comparison": "Referentna usporedba",
    "cases.independent_cost_check_on_a_design.step.benchmark.out.variances": "Odstupanja cijena",
    "cases.independent_cost_check_on_a_design.step.benchmark.title": "Neovisno usporedi s referentnim vrijednostima",
    "cases.independent_cost_check_on_a_design.step.benchmark.what": "Usporedite cijene velike vrijednosti i ukupnu cijenu po kvadratnom metru s referentnom bazom troškova i usporedivim projektima, neovisno o brojevima već sadržanim u troškovniku.",
    "cases.independent_cost_check_on_a_design.step.benchmark.why": "Neovisna provjera koja samo ponovno čita isti izvor ničim ne dokazuje. Usporedba s odvojenom referentnom bazom ono je što mišljenju daje težinu.",
    "cases.independent_cost_check_on_a_design.step.open.in.bill": "Troškovnik projekta",
