    "cases.inspect_and_close_ncr.step.ncr.title": "Prijavi neusklađenost",
    "cases.inspect_and_close_ncr.step.ncr.what": "Kod neuspjeha prijavite neusklađenost izravno iz inspekcije. Jasno opišite nedostatak, priložite fotografije i pali kontrolni popis, i imenujte stranu koja ga mora otkloniti te rok do kada.",
    "cases.inspect_and_close_ncr.step.ncr.why": "Neusklađenost pretvara labavu pritužbu u praćenu mjeru s imenovanim odgovornim i rokom. Nedostatak spomenut usput bude ugrađen i zaboravljen, dok nedostatak u registru biva praćen dok se ne otkloni.",
    "cases.inspect_and_close_ncr.title": "Pregledaj rad i zatvori neusklađenost",
    "cases.issue_a_controlled_drawing_revision.desc": "Registrirajte novu reviziju nacrta, označite staru kao zastarjelu, dostavite je svakoj struci koja gradi prema njoj i potvrdite da je važeći list stvarno onaj koji je na zidu na gradilištu.",
    "cases.issue_a_controlled_drawing_revision.step.register.in.drawing": "Nova revizija nacrta",
