    "cases.produce_a_short_interval_lookahead.step.pull.out.tasks": "Aktivnosti na razini zadataka",
    "cases.produce_a_short_interval_lookahead.step.pull.title": "Izvucite sljedeće tjedne",
    "cases.produce_a_short_interval_lookahead.step.pull.what": "Uzmite radove za sljedeća dva do tri tjedna iz glavnog programa i razložite zadatke na razinu na kojoj poslovođa stvarno planira: betoniranje, dizanje, prostoriju, a ne sažetu traku.",
    "cases.produce_a_short_interval_lookahead.step.pull.why": "Glavni program postavlja smjer, ali je pregrub za vođenje tjedna. Razlaganje kratkoročnog rada na stvarne aktivnosti čini plan nečim za što se ekipa može smatrati odgovornom.",
    "cases.produce_a_short_interval_lookahead.title": "Izrada kratkoročnog plana",
    "cases.project_end_to_end.desc": "Provedite posao od samog početka do primopredaje. Otvorite ga, ocijenite radove, isplanirajte program, pratite ga na gradilištu, i uredno ga zatvorite. Pet koraka kroz cijeli životni ciklus.",
    "cases.project_end_to_end.step.create.in.brief": "Sažetak projekta",
