    "cases.run_a_toolbox_talk_and_record_attendance.step.follow-up.title": "Pratite svaku mjeru",
    "cases.run_a_toolbox_talk_and_record_attendance.step.follow-up.what": "Ako je razgovor otkrio nedostajuću kontrolu, pokvareni alat ili prazninu u opremi, otvorite mjeru s odgovornom osobom i rokom te provjerite je li zatvorena prije početka aktivnosti.",
    "cases.run_a_toolbox_talk_and_record_attendance.step.follow-up.why": "Razgovor koji ukaže na opasnost, a zatim se ništa ne poduzme gore je od izostanka razgovora, jer je rizik sada poznat, ali neupravljan. Praćenje mjere do kraja stvarno štiti ekipu.",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.in.hazards": "Poznate opasnosti na gradilištu",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.in.plan": "Dnevni plan rada",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.out.activity": "Odabrana aktivnost visokog rizika",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.out.hazard": "Utvrđena glavna opasnost",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.title": "Odaberite aktivnost i opasnost",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.what": "Pogledajte planirani rad za danas i odaberite aktivnost s najvišim rizikom, zatim zabilježite glavnu opasnost s kojom će se ekipa suočiti: rad na visini, dizanje, vruće radove, aktivne instalacije ili što god vodi dan.",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.why": "Razgovor o sigurnosti djeluje samo kad se odnosi na posao koji je ekipa toga jutra pred sobom. Povezivanje sa stvarnom aktivnošću i stvarnom opasnošću tjera ekipu da sluša, a ne samo kimne glavom.",
    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.in.activity": "Odabrana aktivnost",
    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.in.hazard": "Utvrđena opasnost",
