    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.out.talk": "Pripremljene točke razgovora",
    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.title": "Pripremite razgovor",
    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.what": "Zapišite nekoliko jasnih točaka za razgovor: opasnost, postojeće kontrole, potrebnu zaštitnu opremu i postupak u slučaju da nešto krene po zlu, kako biste ga mogli održati u nekoliko minuta.",
    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.why": "Kratak, unaprijed pripremljen razgovor djeluje bolje od improvizacije. Zapisane kontrole osiguravaju da se ništa važno ne zaboravi pred ekipom.",
    "cases.run_a_toolbox_talk_and_record_attendance.title": "Održite razgovor o sigurnosti i zabilježite prisutnost",
    "cases.run_reactive_fm_service_after_handover.desc": "Riješite kvar onako kako bi to trebao raditi upravitelj zgrade: prijavite reaktivni zahtjev na imovinu, obradite ga uz dostupne podatke o jamstvu i tehničkoj dokumentaciji te ga zatvorite provjernom kontrolom.",
    "cases.run_reactive_fm_service_after_handover.step.asset.in.record": "Zapis o imovini",
    "cases.run_reactive_fm_service_after_handover.step.asset.in.request": "Prijavljen zahtjev za servis",
