    "cases.run_reactive_fm_service_after_handover.step.asset.what": "Otvorite zapis o imovini kako biste vidjeli marku i model, lokaciju i, ključno, je li još pod jamstvom te što kaže priručnik za rad i održavanje. Odatle preuzmite rezervni dio ili postupak.",
    "cases.run_reactive_fm_service_after_handover.step.asset.why": "Popravak jedinice koja je još pod jamstvom o vlastitom trošku je novac bačen kroz prozor. Zapis o imovini prije početka posla govori serviseru tko plaća i kako proizvođač propisuje popravak.",
    "cases.run_reactive_fm_service_after_handover.step.request.in.asset": "Zahvaćena imovina",
    "cases.run_reactive_fm_service_after_handover.step.request.in.fault": "Prijavljen kvar",
    "cases.run_reactive_fm_service_after_handover.step.request.out.request": "Prijavljen zahtjev za servis",
    "cases.run_reactive_fm_service_after_handover.step.request.out.target": "Postavljen ciljani rok odgovora",
    "cases.run_reactive_fm_service_after_handover.step.request.title": "Prijavite reaktivni zahtjev",
    "cases.run_reactive_fm_service_after_handover.step.request.what": "Prijavite zahtjev za servis vezan uz konkretnu imovinu koja je otkazala, s kvarom, lokacijom i prioritetom, tako da se prati od prijave do popravka umjesto da leži u pretincu. Postavite ciljani rok odgovora.",
    "cases.run_reactive_fm_service_after_handover.step.request.why": "Kvar koji nije prijavljen uz imovinu nitko ne može pratiti niti dokazati da je popravljen. Povezivanje s imovinom od prvog poziva kasnije pokazuje koje jedinice stalno otkazuju i je li ciljani rok odgovora ispunjen.",
    "cases.run_reactive_fm_service_after_handover.step.verify.in.repair": "Dovršen popravak",
    "cases.run_reactive_fm_service_after_handover.step.verify.in.request": "Otvoren zahtjev za servis",
