    "cases.track_a_design_change_to_site_record.step.instruct.what": "Zabilježite uputu koja ovlašćuje izmjenu na gradilištu, povezanu s revizijom nacrta koja je nosi, uz naznaku vjerojatnog utjecaja na trošak i rok.",
    "cases.track_a_design_change_to_site_record.step.instruct.why": "Povezivanje upute s točnom revizijom sprječava kasniji spor oko toga koja je verzija izmjene stvarno dogovorena.",
    "cases.track_a_design_change_to_site_record.step.revise.in.change": "Projektna izmjena",
    "cases.track_a_design_change_to_site_record.step.revise.in.previous": "Prethodna verzija nacrta",
